import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const LeagueGeneration = () => {
    const [clasificacion, setClasificacion] = useState({});
    const [calendario, setCalendario] = useState({});
    const navigate = useNavigate();

    const mezclarEquipos = (equipos) => {
        const copia = [...equipos];
        for (let i = copia.length - 1; i > 0; i--) {
            const j = Math.floor(Math.random() * (i + 1));
            [copia[i], copia[j]] = [copia[j], copia[i]];
        }
        return copia;
    };

    const agruparEquiposPorLiga = (equipos) => {
        return equipos.reduce((ligas, equipo) => {
            if (!ligas[equipo.liga]) ligas[equipo.liga] = [];
            ligas[equipo.liga].push(equipo);
            return ligas;
        }, {});
    };

    useEffect(() => {
        const generarLigas = async () => {
            try {
                let equiposAlmacenados = JSON.parse(localStorage.getItem("equipos")) || [];
        
                // ✅ NUEVO: Redistribuir equipos en grupos válidos
                equiposAlmacenados = redistribuirEquipos(equiposAlmacenados);
        
                const ligas = agruparEquiposPorLiga(equiposAlmacenados);
                const clasificacionesPorLiga = {};
                const calendariosPorLiga = {};
                const descensosPorLigaTemp = {};
                const ascensosPorLigaTemp = {};
                const playoffsPorLigaTemp = {};
        
                Object.entries(ligas).forEach(([liga, equiposLiga]) => {
                    const equiposAleatorios = mezclarEquipos(equiposLiga);
        
                    clasificacionesPorLiga[liga] = crearClasificacion(equiposAleatorios);
                    calendariosPorLiga[liga] = generarJornadasLiga(equiposAleatorios);
        
                    if (liga.includes("Primera RFEF")) {
                        descensosPorLigaTemp[liga] = 5;
                        ascensosPorLigaTemp[liga] = 1;
                        playoffsPorLigaTemp[liga] = 4;
                    } else if (liga.includes("Segunda RFEF")) {
                        descensosPorLigaTemp[liga] = 5;
                        ascensosPorLigaTemp[liga] = 1;
                        playoffsPorLigaTemp[liga] = 4;
                    } else if (liga.includes("Tercera RFEF")) {
                        descensosPorLigaTemp[liga] = 3;
                        ascensosPorLigaTemp[liga] = 1;
                        playoffsPorLigaTemp[liga] = 4;
                    } else if (liga === "La Liga") {
                        descensosPorLigaTemp[liga] = 3;
                    } else if (liga === "Liga 2") {
                        descensosPorLigaTemp[liga] = 4;
                        ascensosPorLigaTemp[liga] = 2;
                        playoffsPorLigaTemp[liga] = 4;
                    }
                });
        
                // Guardar todo en localStorage
                setClasificacion(clasificacionesPorLiga);
                setCalendario(calendariosPorLiga);
        
                localStorage.setItem("equipos", JSON.stringify(equiposAlmacenados));
                localStorage.setItem("clasificacion", JSON.stringify(clasificacionesPorLiga));
                localStorage.setItem("calendario", JSON.stringify(calendariosPorLiga));
                localStorage.setItem("descensos", JSON.stringify(descensosPorLigaTemp));
                localStorage.setItem("ascensos", JSON.stringify(ascensosPorLigaTemp));
                localStorage.setItem("playoffs", JSON.stringify(playoffsPorLigaTemp));
        
                console.log("Ligas generadas y redistribuidas correctamente.");
            } catch (error) {
                console.error("Error al redistribuir y generar ligas:", error);
                alert("No se pudo procesar el archivo de equipos.");
            }
        };

        generarLigas();
    }, []);

    const crearClasificacion = (equipos) => {
        return equipos.map((equipo) => ({
            id: equipo.id,
            imagen: equipo.imagen,
            nombre: equipo.nombre,
            puntos: 0,
            partidosJugados: 0,
            victorias: 0,
            empates: 0,
            derrotas: 0,
            golesFavor: 0,
            golesContra: 0,
            diferenciaGoles: 0,
        }));
    };

    const generarJornadasLiga = (equipos) => {
        if (equipos.length % 2 !== 0) equipos.push({ id: -1, nombre: "Descanso" });
        const n = equipos.length;
        const mitad = n / 2;
        const jornadas = [];
        const rotacion = equipos.slice(1);

        for (let i = 0; i < n - 1; i++) {
            const jornada = [];
            const izquierda = [equipos[0], ...rotacion.slice(0, mitad - 1)];
            const derecha = rotacion.slice(mitad - 1).reverse();

            for (let j = 0; j < mitad; j++) {
                let local = i % 2 === 0 ? izquierda[j] : derecha[j];
                let visitante = i % 2 === 0 ? derecha[j] : izquierda[j];

                if (local.id !== -1 && visitante.id !== -1) {
                    jornada.push({ local, visitante });
                }
            }
            jornadas.push(jornada);
            rotacion.unshift(rotacion.pop());
        }

        const jornadasVuelta = jornadas.map(j =>
            j.map(({ local, visitante }) => ({
                local: visitante,
                visitante: local,
            }))
        );
        return [...jornadas, ...jornadasVuelta];
    };

    function redistribuirEquipos(equipos) {
        const nuevasLigas = [];
    
        // 1. Separar por categoría
        const primera = equipos.filter(e => e.liga.includes("Primera RFEF"));
        const segunda = equipos.filter(e => e.liga.includes("Segunda RFEF"));
        const tercera = equipos.filter(e => e.liga.includes("Tercera RFEF"));
        const otras = equipos.filter(e => !e.liga.includes("RFEF"));
    
        // ---------- PRIMERA RFEF ----------
        const norte = ["Galicia", "Asturias", "Cantabria", "Castilla y León", "País Vasco", "Navarra", "La Rioja", "Aragón", "Cataluña"];
        const sur = ["Madrid", "Castilla-La Mancha", "Extremadura", "Andalucía", "Ceuta", "Melilla", "Murcia", "Comunidad Valenciana", "Islas Baleares", "Canarias"];
    
        // ---------- PRIMERA RFEF ----------
            const primeraRFEF = equipos.filter(e =>
                e.liga.includes("Primera RFEF") || e.liga === "Liga 2 descendido" || e.liga === "Primera RFEF - ???"
            );

            let grupo1 = primeraRFEF.filter(e => norte.includes(e.comunidad));
            let grupo2 = primeraRFEF.filter(e => sur.includes(e.comunidad));

            // ✅ Balancear grupos geográficamente si sobran en uno
            while (grupo1.length > 20) {
                const trasladado = grupo1.pop();
                grupo2.push(trasladado);
            }
            while (grupo2.length > 20) {
                const trasladado = grupo2.pop();
                grupo1.push(trasladado);
            }

            // ✅ Rellenar si faltan
            grupo1 = completar(grupo1, 20, `Regionales - ${grupo1[0]?.comunidad || "Galicia"}`, "Primera RFEF - Grupo 1");
            grupo2 = completar(grupo2, 20, `Regionales - ${grupo2[0]?.comunidad || "Madrid"}`, "Primera RFEF - Grupo 2");

            grupo1.forEach(e => e.liga = "Primera RFEF - Grupo 1");
            grupo2.forEach(e => e.liga = "Primera RFEF - Grupo 2");

            nuevasLigas.push(...grupo1, ...grupo2);
    
        // ---------- SEGUNDA RFEF ----------
        const regiones = {
            "Grupo 1": ["Galicia", "Asturias", "Cantabria", "Castilla y León"],
            "Grupo 2": ["País Vasco", "Navarra", "La Rioja"],
            "Grupo 3": ["Cataluña", "Comunidad Valenciana", "Aragón", "Islas Baleares"],
            "Grupo 4": ["Andalucía", "Ceuta", "Melilla", "Murcia", "Extremadura"],
            "Grupo 5": ["Madrid", "Castilla-La Mancha", "Canarias"]
        };
    
        Object.entries(regiones).forEach(([grupo, comunidades]) => {
            let subgrupo = segunda.filter(e => comunidades.includes(e.comunidad));
            subgrupo = completar(subgrupo, 18, `Regionales - ${comunidades[0]}`, `Segunda RFEF - ${grupo}`);
            subgrupo.forEach(e => e.liga = `Segunda RFEF - ${grupo}`);
            nuevasLigas.push(...subgrupo);
        });
    
        // ---------- TERCERA RFEF ----------
        const comunidades = [...new Set(tercera.map(e => e.comunidad))];
    
        comunidades.forEach(comunidad => {
            let grupo = tercera.filter(e => e.comunidad === comunidad);
            grupo = completar(grupo, 18, `Regionales - ${comunidad}`, `Tercera RFEF - ${comunidad}`);
            grupo.forEach(e => e.liga = `Tercera RFEF - ${comunidad}`);
            nuevasLigas.push(...grupo);
        });
    
        // Juntar todo
        return [...nuevasLigas, ...otras];
    }
    
    function completar(equipos, objetivo, categoriaOrigen, ligaDestino) {
        const faltan = objetivo - equipos.length;
        for (let i = 0; i < faltan; i++) {
            equipos.push({
                id: Date.now() + i,
                nombre: `Equipo Regional ${i + 1}`,
                liga: ligaDestino,
                comunidad: categoriaOrigen.split(" - ")[1],
                imagen: "/assets/images/default.png",
                estadisticas: {
                    partidosJugados: 0,
                    victorias: 0,
                    empates: 0,
                    derrotas: 0,
                    golesFavor: 0,
                    golesContra: 0
                },
                player: false
            });
        }
        return equipos;
    }
    
    function balancearGrupos(grupo1, grupo2, maxPorGrupo, categoria) {
        while (grupo1.length > maxPorGrupo) {
            const candidato = grupo1.pop();
            grupo2.push(candidato);
        }
        while (grupo2.length > maxPorGrupo) {
            const candidato = grupo2.pop();
            grupo1.push(candidato);
        }
    
        // Si uno tiene menos, tomar más cercanos (norte/sur)
        while (grupo1.length < maxPorGrupo || grupo2.length < maxPorGrupo) {
            // No se puede completar si no hay más candidatos
            break;
        }
    }
    
    const handleContinue = () => {
        navigate("/main-menu");
    };

    return (
        <div className="league-generation">
            <h1>Ligas Generadas</h1>
            {Object.keys(clasificacion).map((liga) => (
                <div key={liga}>
                    <h2>{liga}</h2>
                </div>
            ))}
            <button onClick={handleContinue}>Continuar</button>
        </div>
    );
};

export default LeagueGeneration;
